325	enrichRowWithGroupInfo(row: any) {
326	  if (row.tagged_group_id && this.groupsList.length > 0) {
327	    const group = this.groupsList.find(g => g.id === row.tagged_group_id);
328	    if (group) {
329	      row.tagged_group_name = group.name;
330	      if (group.member_user_ids && Array.isArray(group.member_user_ids)) {
331	        row.tagged_users = group.member_user_ids;
332	        const memberNames = group.member_user_ids.map(id => {
333	          const user = this.usersList.find(u => u.id === id);
334	          return user ? `${user.name} ${user.lastname}` : `User ${id}`;
335	        });
336	        row.tagged_group_members_names = memberNames.join(', ');
337	      } else {
338	        row.tagged_users = [];
339	        row.tagged_group_members_names = 'No members';
340	      }
341	    }
342	  } else if (!row.tagged_users) {
343	    row.tagged_users = [];
344	  }
345	}
