347	isUserMentionedInRow(row: any): boolean {
348	  if (!this.currentUserId || !row) return false;
349	  const userId = Number(this.currentUserId);
350	  if (Number(row.assignee_id) === userId) return true;
351	  if (row.has_reply_tagging_current_user) return true;
352	  if (Array.isArray(row.tagged_users) && row.tagged_users.map(Number).includes(userId)) return true;
353	  return false;
354	}
