381	  openGroupManager(row: any, event: Event) {
382	    event.stopPropagation();
383	    if (!row.tagged_group_id) return;
384	    
385	    // Find the group from our list
386	    const group = this.groupsList.find(g => g.id === row.tagged_group_id);
387	    if (group) {
388	      // Create a copy to work with
389	      this.selectedGroupForEdit = { ...group, member_user_ids: [...(group.member_user_ids || [])] };
390	      this.groupMemberSearchText = '';
391	      this.filteredGroupUsers = this.usersList.filter(u => !this.isUserInGroup(u.id));
392	    }
