401	  filterGroupUsers(searchText: string) {
402	    this.groupMemberSearchText = searchText;
403	    const lower = (searchText || '').toLowerCase();
404	    
405	    this.filteredGroupUsers = this.usersList.filter(u => {
406	      const nameMatch = !lower || 
407	        u.name?.toLowerCase().includes(lower) || 
408	        u.lastname?.toLowerCase().includes(lower);
409	      return nameMatch;
410	    });
411	  }
412	
413	  isUserInGroup(userId: number): boolean {
414	    if (!this.selectedGroupForEdit?.member_user_ids) return false;
415	    return this.selectedGroupForEdit.member_user_ids.includes(userId);
416	  }
417	
418	  getMemberName(memberId: number): string {
419	    const user = this.usersList.find(u => u.id === memberId);
420	    return user ? `${user.name} ${user.lastname}` : `User ${memberId}`;
421	  }
422	
423	  addUserToGroup(group: any, user: any) {
424	    if (!group || !user) return;
425	    if (this.isUserInGroup(user.id)) return;
426	    
427	    group.member_user_ids.push(user.id);
428	    this.updateGroupMembers(group);
429	  }
430	
431	  removeUserFromGroup(group: any, userId: number) {
432	    if (!group) return;
433	    
434	    const index = group.member_user_ids.indexOf(userId);
435	    if (index > -1) {
436	      group.member_user_ids.splice(index, 1);
437	      this.updateGroupMembers(group);
438	    }
439	  }
440	
441	  updateGroupMembers(group: any) {
442	    this.licensingService.updateGroup(group.id, { member_user_ids: group.member_user_ids })
443	      .subscribe({
444	        next: (updatedGroup) => {
445	          // Update the group in our local list
446	          const idx = this.groupsList.findIndex(g => g.id === group.id);
447	          if (idx > -1) {
448	            this.groupsList[idx] = updatedGroup;
449	          }
450	          
451	          // Update the row data to reflect the changes
452	          this.processGroupInfo(window["data"]);
453	          this.processGroupInfo(window["packageData"]);
454	          
455	          // Update filtered users list
456	          this.filteredGroupUsers = this.usersList.filter(u => !this.isUserInGroup(u.id));
457	          
458	          this._snackBar.open('Group members updated', 'Close', { duration: 3000 });
459	        },
460	        error: (err) => {
461	          this._snackBar.open('Failed to update group: ' + (err.message || 'Unknown error'), 'Close', { duration: 5000 });
462	        }
463	      });
464	  }
465	}
