687	  dateComparator(date1, date2, nodeA, nodeB, isInverted) {
688	    function formatDate(input) {
689	      if (input == null) return ''
690	      if (input.includes("-")) {
691	        var datePart = input.match(/\d+/g),
692	          year = datePart[0].substring(), // get only two digits
693	          month = datePart[1], day = datePart[2];
694	        return month + '/' + day + '/' + year;
695	      } else {
696	        return input
697	      }
698	    }
699	
700	    function monthToComparableNumber(date) {
701	
702	      if (date === undefined || date === null || date.length !== 10) {
703	        return date.length;
704	      }
705	      var yearNumber = date.substring(6, 10);
706	      var dayNumber = date.substring(3, 5);
707	      var monthNumber = date.substring(0, 2);
708	      var result = yearNumber * 10000 + monthNumber * 100 + dayNumber;
709	      return result;
710	    }
711	
712	
713	    date1 = formatDate(date1)
714	
715	    date2 = formatDate(date2)
716	
717	    var date1Number = monthToComparableNumber(date1);
718	    var date2Number = monthToComparableNumber(date2);
719	    if (date1Number === null && date2Number === null) {
720	      return 0;
721	    }
722	    if (date1Number === null) {
723	      return -1;
724	    }
725	    if (date2Number === null) {
726	      return 1;
727	    }
728	    return date1Number - date2Number;
729	  }
