667	  mapHeaderValues(colHeadersData: any, fetchedGroups: any, header: any) {
668	    const headerLower = String(header).toLowerCase().trim();
669	    const column = colHeadersData.find(
670	      (h: any) => h?.headerName && h.headerName.toLowerCase().trim() === headerLower
671	    );
672	    if (!column) return;
673	
674	    const rowFieldKey =
675	      column.field != null && String(column.field).trim() !== ''
676	        ? column.field
677	        : headerLower.replace(/\s+/g, '_');
678	
679	    const headerKey = this.normalizeMerchTypeLabel(headerLower);
680	
681	    column.valueGetter = (m) => {
682	      const group = fetchedGroups.find((g: any) => g?.divCode_id === m?.data?.divisioncode_id);
683	      const groupList = group?.merchGroupHeaders?.find(
684	        (g: any) => this.normalizeMerchTypeLabel(g?.mgTypeDesc) === headerKey
685	      )?.merchGroups;
686	
687	      if (!groupList) return null;
688	
689	      return groupList.find((mg: any) => mg?.mg_id === m?.data?.[rowFieldKey])?.mg_desc;
690	    };
691	  }
