784	  private openDeleteConfirmDialog(rows: any[], api?: GridApi): void {
785	    const artPieces = rows
786	      .map((r) => ({
787	        id: r.id,
788	        description: r.description,
789	        art_number: r.art_number,
790	      }))
791	      .filter((p) => p.id != null);
792	
793	    if (!artPieces.length) {
794	      this._snackBar.open('No valid art pieces selected.', 'close');
795	      return;
796	    }
797	
798	    const ids = artPieces.map((p) => p.id) as number[];
799	
800	    this.loaderService.increment();
801	    this.artPieceService.checkDeleteEligibility(ids).subscribe({
802	      next: (checkRes: any) => {
803	        this.loaderService.decrement();
804	        if (checkRes?.canDelete !== true) {
805	          this._snackBar.open(this.getDeleteBlockedSnackMessage(ids, checkRes), 'close', {
806	            duration: this.deleteBlockedSnackDurationMs,
807	          });
808	          return;
809	        }
810	
811	        const count = artPieces.length;
812	        const single = artPieces[0];
813	        const label =
814	          count === 1
815	            ? (single.art_number || single.description || `ID ${single.id}`)
816	            : `${count} art pieces`;
817	
818	        const dialogRef = this.dialog.open(ArtPieceDeleteConfirmDialogComponent, {
819	          width: '440px',
820	          autoFocus: false,
821	          data: {
822	            title: count === 1 ? 'Delete art piece' : 'Delete art pieces',
823	            message:
824	              count === 1
825	                ? `Are you sure you want to permanently delete "${label}"? This cannot be undone.`
826	                : `Are you sure you want to permanently delete ${count} selected art pieces? This cannot be undone.`,
827	          },
828	        });
829	
830	        dialogRef.afterClosed().subscribe((confirmed) => {
831	          if (!confirmed) {
832	            return;
833	          }
834	          this.performDelete(ids, api);
835	        });
836	      },
837	      error: (err) => {
838	        this.loaderService.decrement();
839	        const msg =
840	          err?.error?.message ||
841	          'Could not verify whether this art piece can be deleted.';
842	        this._snackBar.open(msg, 'close', { duration: this.deleteBlockedSnackDurationMs });
843	      },
844	    });
845	  }
