847	  private getDeleteBlockedSnackMessage(ids: number[], res: any): string {
848	    const linkedNums = Array.isArray(res?.linkedItemNums)
849	      ? res.linkedItemNums.filter((n: string) => n != null && String(n).trim() !== '')
850	      : [];
851	
852	    const linkedMessageSingle =
853	      'Cannot delete: an item was created using this art piece.';
854	    const bulkLinkedMessage =
855	      'Cannot delete: one or more selected art pieces have items created from them.';
856	
857	    if (res?.code === 'LINKED_ITEMS') {
858	      const base = ids.length > 1 ? bulkLinkedMessage : linkedMessageSingle;
859	      if (linkedNums.length > 0) {
860	        return `${base} Item num(s): ${linkedNums.join(', ')}.`;
861	      }
862	      return `${base} Check the item library for the linked item record.`;
863	    }
864	    return res?.message || 'Unable to delete art piece(s).';
865	  }
