867	  private performDelete(ids: number[], api?: GridApi): void {
868	    if (!ids.length) {
869	      return;
870	    }
871	    this.loaderService.increment();
872	    this.artPieceService.deleteArtPieces(ids).subscribe({
873	      next: (res: any) => {
874	        this.loaderService.decrement();
875	        const gridApi = api ?? this.gridApi;
876	        if (res?.status === true) {
877	          this._snackBar.open(
878	            ids.length === 1
879	              ? 'Art piece deleted successfully.'
880	              : `${ids.length} art pieces deleted successfully.`,
881	            'close',
882	            { duration: 3000 }
883	          );
884	          gridApi?.deselectAll();
885	          gridApi?.refreshServerSide({ purge: false });
886	          this.selectedArtPieceCount = 0;
887	        } else {
888	          this._snackBar.open(this.getDeleteBlockedSnackMessage(ids, res), 'close', {
889	            duration: this.deleteBlockedSnackDurationMs,
890	          });
891	        }
892	      },
893	      error: (err) => {
894	        this.loaderService.decrement();
895	        const msg =
896	          err?.error?.message || 'An error occurred while deleting art piece(s).';
897	        this._snackBar.open(msg, 'close', { duration: 6000 });
898	      },
899	    });
900	  }
