1028	  async getBase64FromUrl(url: string): Promise<string> {
1029	    if (!url) return '';
1030	    
1031	    try {
1032	      const response = await fetch(url);
1033	      const blob = await response.blob();
1034	      return new Promise((resolve, reject) => {
1035	        const reader = new FileReader();
1036	        reader.readAsDataURL(blob);
1037	        reader.onloadend = () => {
1038	          resolve(reader.result as string);
1039	        };
1040	        reader.onerror = reject;
1041	      });
1042	    } catch (error) {
1043	      return '';
1044	    }
1045	  }
